2	import { runScenario } from "./claim-office.js";
3	
4	describe("MHPCO Claim Office", () => {
5	  describe("Quote — base premiums (single item)", () => {
6	    it("should quote 105 G for a single plain sword (100 base + 5 fee)", () => {
7	      const result = runScenario({
8	        customer: { yearsWithMHPCO: 0 },
9	        steps: [{ op: "quote", items: [{ type: "sword" }] }],
10	      });
11	
12	      expect(result.results[0]).toEqual({ premium: 105 });
13	    });
14	    it.todo("should quote 65 G for a single plain amulet (60 base + 5 fee)");
15	    it.todo("should quote 85 G for a single plain staff (80 base + 5 fee)");
16	    it.todo("should quote 45 G for a single plain potion (40 base + 5 fee)");
17	    it.todo("should quote 30 G for a single rune (25 base + 5 fee)");
18	    it.todo("should quote 30 G for a single moonstone (25 base + 5 fee)");
19	  });
20	
21	  describe("Quote — empty policy", () => {
22	    it.todo("should quote 5 G for an empty item list (only processing fee)");
23	  });
24	
25	  describe("Quote — component building blocks", () => {
26	    it.todo("should charge 50 G base for 2 runes (no block)");
27	    it.todo("should charge 60 G base for 3 runes (block of 3 alike applies)");
28	    it.todo("should charge 100 G base for 4 runes (no block — block requires exactly 3)");
29	    it.todo("should charge 175 G base for 7 runes (one block of 3 + 4 leftover)");
30	    it.todo("should charge 75 G base for 2 runes + 1 moonstone (no block: different types)");
31	    it.todo("should charge 120 G base for 3 runes + 3 moonstones (two separate blocks)");
32	  });
33	
34	  describe("Quote — item-specific modifiers", () => {
35	    it.todo("should add 50% curse surcharge to a cursed sword's base premium");
36	    it.todo("should add 30% high-enchantment surcharge to a sword with enchantment exactly 5");
37	    it.todo("should not add high-enchantment surcharge to a sword with enchantment 4");
38	    it.todo("should apply both curse and high-enchantment surcharges to a cursed sword with enchantment 5");
39	  });
40	
41	  describe("Quote — policy-wide modifiers", () => {
42	    it.todo("should apply 20% loyalty discount for a customer with exactly 2 years with MHPCO");
43	    it.todo("should not apply loyalty discount for a customer with fewer than 2 years");
44	    it.todo("should add 10% first-insurance surcharge on the policy base premium");
45	    it.todo("should apply 15% follow-up discount on each quote after the customer's first in a scenario");
46	  });
47	
48	  describe("Quote — modifier scope on multi-item policies", () => {
49	    it.todo("should apply the curse surcharge only to the cursed item's base premium, not the policy total");
50	  });
51	
52	  describe("Quote — rounding", () => {
53	    it.todo("should round the final premium up to the next whole G");
54	  });
55	
56	  describe("Quote — integration examples", () => {
57	    it.todo("should quote 165 G for a newcomer's cursed steel sword (enchantment 3, 0 years)");
58	    it.todo("should quote 160 G for a long-standing customer's second quote (cursed steel sword enchantment 7, 3 years)");
59	  });
60	
61	  describe("Claim — standard reimbursement", () => {
62	    it.todo("should pay 400 G for a steel sword (enchantment 3) damaged 500 G (full minus 100 deductible)");
63	    it.todo("should pay 100 G for a rune damaged 200 G (full minus 100 deductible, no special clause)");
64	  });
65	
66	  describe("Claim — special clauses", () => {
67	    it.todo("should reimburse 50% then deduct for a steel sword enchantment 9 damaged 1000 G → 400 G");
68	    it.todo("should fully reimburse then deduct for a dragon-material sword enchantment 5 damaged 800 G → 700 G");
69	    it.todo("should apply the 50% rule then deduct for a dragon sword enchantment 8 damaged 1000 G → 400 G");
70	    it.todo("should let the 50% rule win over dragon material for a dragon sword enchantment 9 damaged 1000 G → 400 G");
71	  });
72	
73	  describe("Claim — deductible per damage event", () => {
74	    it.todo("should apply the 100 G deductible once per damaged item (sword 500 + amulet 300 → 600 G)");
75	  });
76	
77	  describe("Claim — rounding", () => {
78	    it.todo("should round the final payout down to the previous whole G");
79	  });
80	
81	  describe("Claim — cap based on unmodified insurance sum", () => {
82	    it.todo("should cap a sword+amulet policy at 3200 G (sum 1600)");
83	    it.todo("should cap a sword+3-runes policy at 3500 G (sum 1750, block discount does not lower the sum)");
84	    it.todo("should cap a two-sword policy at 4000 G (sum 2000)");
85	  });
86	
87	  describe("Claim — cap exhaustion across successive claims", () => {
88	    it.todo("should report remainingCap after a single claim (sword cap 2000, claim 1500 → payout 1400, remaining 600)");
89	    it.todo("should limit a later claim to the remaining cap (second claim 1500 → payout 600, remaining 0)");
