91	
92	  describe("Claim — multiple items of the same type", () => {
93	    it.todo("should treat each same-type damage entry as a separate damage with its own deductible");
94	  });
95	
96	  describe("CLI scenario output shape", () => {
97	    it.todo("should return a results array of the same length and order as the input steps");
98	    it.todo("should return { premium } for a quote step and { payout, remainingCap } for a claim step");
99	  });
100	
101	  describe("Error handling", () => {
102	    it.todo("should reject a quote containing an unknown item type (e.g. broomstick)");
103	    it.todo("should reject a claim whose damage item is not part of the policy");
104	    it.todo("should reject a claim with more same-type damage entries than the policy covers");
105	    it.todo("should reject a claim with a negative damage amount");
106	  });
107	});
